+namespace Microsoft.Integration.Shopify;
+
+using Microsoft.Sales.Document;
+using Microsoft.Foundation.Enums;
+
+/// <summary>
+/// Codeunit Shpfy Copy Sales Doc. Handler (ID 30181).
+/// Handles clearing of Shopify Order Id and Order No. when copying sales documents.
+/// </summary>
+codeunit 30181 "Shpfy Copy Sales Doc. Handler"
+{
+    Access = Internal;
+
+    [EventSubscriber(ObjectType::Codeunit, Codeunit::"Copy Document Mgt.", 'OnAfterCopySalesHeader', '', false, false)]
+    local procedure OnAfterCopySalesHeaderClearShopifyFields(var ToSalesHeader: Record "Sales Header"; OldSalesHeader: Record "Sales Header"; FromSalesHeader: Record "Sales Header"; FromDocType: Enum "Sales Document Type From")
+    begin
+        // Clear Shopify Order Id and Order No. fields to ensure the copied document can be synced to Shopify
+        ToSalesHeader."Shpfy Order Id" := 0;
+        ToSalesHeader."Shpfy Order No." := '';
+    end;
+}

