+    local procedure ApplyNonDeductibleVATToJobJnlLine(var JobJnlLine: Record "Job Journal Line"; GenJnlLine: Record "Gen. Journal Line")
+    var
+        Currency: Record Currency;
+        CurrencyExchRate: Record "Currency Exchange Rate";
+        NDVATAmountLCY: Decimal;
+        NDVATAmount: Decimal;
+        NDVATAmountJobCurrency: Decimal;
+        NDVATAmountPerUnitLCY: Decimal;
+        NDVATAmountPerUnit: Decimal;
+    begin
+        NDVATAmountLCY := GenJnlLine."Non-Deductible VAT Amount LCY";
+        NDVATAmount := GenJnlLine."Non-Deductible VAT Amount";
+
+        // Always use LCY amount for Unit Cost (LCY)
+        if JobJnlLine."Unit Cost" > 0 then begin
+            JobJnlLine."Unit Cost (LCY)" += Abs(Round(NDVATAmountLCY / JobJnlLine.Quantity));
+            JobJnlLine."Total Cost (LCY)" += Abs(NDVATAmountLCY);
+        end else begin
+            JobJnlLine."Unit Cost (LCY)" += Round(NDVATAmountLCY / JobJnlLine.Quantity);
+            JobJnlLine."Total Cost (LCY)" += NDVATAmountLCY;
+        end;
+
+        // Convert VAT amount to Job Currency if different from Gen. Journal Line currency
+        if JobJnlLine."Currency Code" = '' then begin
+            // Job has no currency (uses LCY), use the LCY amount
+            if JobJnlLine."Unit Cost" > 0 then begin
+                JobJnlLine."Unit Cost" += Abs(Round(NDVATAmountLCY / JobJnlLine.Quantity));
+                JobJnlLine."Total Cost" += Abs(NDVATAmountLCY);
+            end else begin
+                JobJnlLine."Unit Cost" += Round(NDVATAmountLCY / JobJnlLine.Quantity);
+                JobJnlLine."Total Cost" += NDVATAmountLCY;
+            end;
+        end else begin
+            // Job has a currency, convert VAT amount from LCY to Job currency
+            Currency.Get(JobJnlLine."Currency Code");
+            NDVATAmountJobCurrency := Round(
+                CurrencyExchRate.ExchangeAmtLCYToFCY(
+                    GenJnlLine."Posting Date",
+                    JobJnlLine."Currency Code",
+                    NDVATAmountLCY,
+                    JobJnlLine."Currency Factor"),
+                Currency."Amount Rounding Precision");
+
+            if JobJnlLine."Unit Cost" > 0 then begin
+                JobJnlLine."Unit Cost" += Abs(Round(NDVATAmountJobCurrency / JobJnlLine.Quantity, Currency."Unit-Amount Rounding Precision"));
+                JobJnlLine."Total Cost" += Abs(NDVATAmountJobCurrency);
+            end else begin
+                JobJnlLine."Unit Cost" += Round(NDVATAmountJobCurrency / JobJnlLine.Quantity, Currency."Unit-Amount Rounding Precision");
+                JobJnlLine."Total Cost" += NDVATAmountJobCurrency;
+            end;
+        end;
+    end;
